{
  "name": "Gemini Bingo Blitz",
  "description": "A high-energy, AI-enhanced multiplayer-style Bingo game with a live Gemini commentator and dynamic card generation.",
  "requestFramePermissions": []
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export type BingoColumn = 'B' | 'I' | 'N' | 'G' | 'O';

export interface BingoCell {
  number: number | 'FREE';
  isMarked: boolean;
  isWinningCell: boolean;
}

export type BingoCard = BingoCell[][];

export interface GameState {
  drawnNumbers: number[];
  currentBall: number | null;
  card: BingoCard;
  isGameOver: boolean;
  hasWon: boolean;
  commentary: string;
  gameStarted: boolean;
  difficulty: 'Slow' | 'Normal' | 'Fast';
  rivals: RivalPlayer[];
}

export interface RivalPlayer {
  id: string;
  name: string;
  markedCount: number;
  isWinner: boolean;
  avatar: string;
}

import { BingoColumn } from './types';

export const BINGO_RANGES: Record<BingoColumn, { min: number; max: number }> = {
  B: { min: 1, max: 15 },
  I: { min: 16, max: 30 },
  N: { min: 31, max: 45 },
  G: { min: 46, max: 60 },
  O: { min: 61, max: 75 },
};

export const SPEED_MS = {
  Slow: 8000,
  Normal: 5000,
  Fast: 3000,
};

export const RIVAL_NAMES = [
  "Bingo Betty", "Lucky Larry", "Dabber Dan", "Winning Wanda", "Grandma Gertrude", 
  "Salty Sam", "Turbo Todd", "Mellow Mary", "Magic Mike", "Bingo Bandit"
];

import { GoogleGenAI } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const getBingoCommentary = async (number: number): Promise<string> => {
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `The number drawn is ${number}. Give me a classic, witty, or traditional bingo call for this number (max 10 words). e.g., for 22 say 'Two little ducks, twenty-two!'.`,
      config: {
        systemInstruction: "You are a professional, charismatic Bingo caller. Your tone is energetic and entertaining.",
        temperature: 0.9,
      }
    });
    return response.text || `Number ${number}!`;
  } catch (error) {
    console.error("Gemini Commentary Error:", error);
    return `Number ${number}! Get ready!`;
  }
};

export const getWinCelebration = async (name: string): Promise<string> => {
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `${name} just shouted BINGO and won the game! Provide an enthusiastic victory announcement.`,
    });
    return response.text || `BINGO! We have a winner!`;
  } catch {
    return `BINGO! Congratulations!`;
  }
};

import { BingoCard, BingoCell, BingoColumn } from '../types';
import { BINGO_RANGES } from '../constants';

const getRandomInRange = (min: number, max: number, count: number): number[] => {
  const nums = new Set<number>();
  while (nums.size < count) {
    nums.add(Math.floor(Math.random() * (max - min + 1)) + min);
  }
  return Array.from(nums).sort((a, b) => a - b);
};

export const generateCard = (): BingoCard => {
  const columns: BingoColumn[] = ['B', 'I', 'N', 'G', 'O'];
  const card: BingoCard = [];

  for (let i = 0; i < 5; i++) {
    const colKey = columns[i];
    const { min, max } = BINGO_RANGES[colKey];
    const colNumbers = getRandomInRange(min, max, 5);

    const row: BingoCell[] = colNumbers.map((num, idx) => ({
      number: (i === 2 && idx === 2) ? 'FREE' : num,
      isMarked: (i === 2 && idx === 2),
      isWinningCell: false
    }));
    card.push(row);
  }

  // Transpose to get standard card view where rows are accessible
  const rows: BingoCard = Array.from({ length: 5 }, () => Array(5).fill(null));
  for (let c = 0; c < 5; c++) {
    for (let r = 0; r < 5; r++) {
      rows[r][c] = card[c][r];
    }
  }

  return rows;
};

export const checkWin = (card: BingoCard): { hasWon: boolean; winningCells: [number, number][] } => {
  const winningCells: [number, number][] = [];

  // Check rows
  for (let r = 0; r < 5; r++) {
    if (card[r].every(cell => cell.isMarked)) {
      card[r].forEach((_, c) => winningCells.push([r, c]));
      return { hasWon: true, winningCells };
    }
  }

  // Check columns
  for (let c = 0; c < 5; c++) {
    let allMarked = true;
    for (let r = 0; r < 5; r++) {
      if (!card[r][c].isMarked) {
        allMarked = false;
        break;
      }
    }
    if (allMarked) {
      for (let r = 0; r < 5; r++) winningCells.push([r, c]);
      return { hasWon: true, winningCells };
    }
  }

  // Check Diagonal (Top-Left to Bottom-Right)
  let diag1 = true;
  for (let i = 0; i < 5; i++) {
    if (!card[i][i].isMarked) diag1 = false;
  }
  if (diag1) {
    for (let i = 0; i < 5; i++) winningCells.push([i, i]);
    return { hasWon: true, winningCells };
  }

  // Check Diagonal (Top-Right to Bottom-Left)
  let diag2 = true;
  for (let i = 0; i < 5; i++) {
    if (!card[i][4 - i].isMarked) diag2 = false;
  }
  if (diag2) {
    for (let i = 0; i < 5; i++) winningCells.push([i, 4 - i]);
    return { hasWon: true, winningCells };
  }

  return { hasWon: false, winningCells: [] };
};

import React from 'react';
import { BingoCard } from '../types';

interface BingoBoardProps {
  card: BingoCard;
  onCellClick: (row: number, col: number) => void;
  isGameOver: boolean;
}

export const BingoBoard: React.FC<BingoBoardProps> = ({ card, onCellClick, isGameOver }) => {
  const headers = ['B', 'I', 'N', 'G', 'O'];

  return (
    <div className="w-full max-w-md mx-auto bg-white/10 backdrop-blur-md rounded-2xl p-4 shadow-2xl border border-white/20">
      <div className="grid grid-cols-5 gap-2 mb-4">
        {headers.map((h) => (
          <div key={h} className="text-center text-2xl font-bungee text-amber-400 drop-shadow-md">
            {h}
          </div>
        ))}
      </div>
      <div className="grid grid-cols-5 gap-2">
        {card.map((row, rIdx) => (
          <React.Fragment key={rIdx}>
            {row.map((cell, cIdx) => (
              <button
                key={`${rIdx}-${cIdx}`}
                disabled={isGameOver || (cell.number === 'FREE')}
                onClick={() => onCellClick(rIdx, cIdx)}
                className={`
                  aspect-square flex items-center justify-center text-lg md:text-xl font-bold rounded-lg transition-all duration-300 transform hover:scale-105
                  ${cell.isMarked 
                    ? cell.isWinningCell 
                      ? 'bg-gradient-to-br from-green-400 to-green-600 text-white shadow-inner scale-110 rotate-3'
                      : 'bg-gradient-to-br from-amber-400 to-amber-600 text-white shadow-inner opacity-90' 
                    : 'bg-white/90 text-indigo-900 hover:bg-indigo-50'}
                  ${cell.number === 'FREE' ? 'bg-gradient-to-br from-rose-500 to-pink-600 text-xs text-white' : ''}
                  relative
                `}
              >
                {cell.number}
                {cell.isMarked && !cell.isWinningCell && (
                  <div className="absolute inset-0 flex items-center justify-center opacity-30 pointer-events-none">
                    <div className="w-10 h-10 border-4 border-amber-900 rounded-full"></div>
                  </div>
                )}
              </button>
            ))}
          </React.Fragment>
        ))}
      </div>
    </div>
  );
};

import React from 'react';

interface BingoBallProps {
  number: number | null;
  commentary: string;
}

export const BingoBall: React.FC<BingoBallProps> = ({ number, commentary }) => {
  if (number === null) return (
    <div className="h-32 flex items-center justify-center text-gray-400 italic">
      Waiting for the first ball...
    </div>
  );

  const getLetter = (n: number) => {
    if (n <= 15) return 'B';
    if (n <= 30) return 'I';
    if (n <= 45) return 'N';
    if (n <= 60) return 'G';
    return 'O';
  };

  return (
    <div className="flex flex-col items-center gap-4 py-6">
      <div className="relative group">
        <div className="absolute -inset-1 bg-gradient-to-r from-amber-400 to-rose-500 rounded-full blur opacity-25 group-hover:opacity-50 transition duration-1000"></div>
        <div className="relative w-32 h-32 bg-white rounded-full shadow-2xl flex flex-col items-center justify-center border-4 border-indigo-200 floating">
          <span className="text-indigo-400 font-bungee text-xl">{getLetter(number)}</span>
          <span className="text-indigo-900 font-bungee text-5xl leading-none">{number}</span>
        </div>
      </div>
      <div className="bg-indigo-900/40 backdrop-blur-sm px-6 py-2 rounded-full border border-indigo-500/30 text-center animate-pulse">
        <p className="text-amber-300 font-semibold italic text-sm md:text-base">
          "{commentary}"
        </p>
      </div>
    </div>
  );
};

import React from 'react';
import { RivalPlayer } from '../types';

interface RivalListProps {
  rivals: RivalPlayer[];
}

export const RivalList: React.FC<RivalListProps> = ({ rivals }) => {
  return (
    <div className="w-full max-w-xs bg-white/5 backdrop-blur-md rounded-2xl p-4 border border-white/10">
      <h3 className="text-amber-400 font-bungee text-lg mb-4 border-b border-white/10 pb-2">Live Room</h3>
      <div className="space-y-3">
        {rivals.map((rival) => (
          <div key={rival.id} className="flex items-center justify-between group">
            <div className="flex items-center gap-3">
              <img src={rival.avatar} alt="" className="w-8 h-8 rounded-full border border-indigo-400" />
              <div className="flex flex-col">
                <span className={`text-sm font-bold ${rival.isWinner ? 'text-green-400' : 'text-white'}`}>
                  {rival.name} {rival.isWinner && '🏆'}
                </span>
                <div className="w-24 h-1.5 bg-indigo-900 rounded-full overflow-hidden">
                  <div 
                    className="h-full bg-amber-500 transition-all duration-1000"
                    style={{ width: `${(rival.markedCount / 24) * 100}%` }}
                  ></div>
                </div>
              </div>
            </div>
            <span className="text-xs text-indigo-300">{rival.markedCount} / 24</span>
          </div>
        ))}
      </div>
    </div>
  );
};

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { BingoBoard } from './components/BingoBoard';
import { BingoBall } from './components/BingoBall';
import { RivalList } from './components/RivalList';
import { GameState, RivalPlayer, BingoCard } from './types';
import { generateCard, checkWin } from './utils/bingoLogic';
import { SPEED_MS, RIVAL_NAMES } from './constants';
import { getBingoCommentary, getWinCelebration } from './services/geminiService';

const App: React.FC = () => {
  const [state, setState] = useState<GameState>({
    drawnNumbers: [],
    currentBall: null,
    card: generateCard(),
    isGameOver: false,
    hasWon: false,
    commentary: "Welcome to Gemini Bingo Blitz!",
    gameStarted: false,
    difficulty: 'Normal',
    rivals: []
  });

  const timerRef = useRef<NodeJS.Timeout | null>(null);

  const initRivals = (): RivalPlayer[] => {
    return RIVAL_NAMES.slice(0, 5).map((name, i) => ({
      id: `rival-${i}`,
      name,
      markedCount: 0,
      isWinner: false,
      avatar: `https://picsum.photos/seed/${name}/40/40`
    }));
  };

  const startGame = () => {
    setState(prev => ({
      ...prev,
      drawnNumbers: [],
      currentBall: null,
      card: generateCard(),
      isGameOver: false,
      hasWon: false,
      gameStarted: true,
      commentary: "And we're off! Good luck everyone.",
      rivals: initRivals()
    }));
  };

  const resetGame = () => {
    if (timerRef.current) clearInterval(timerRef.current);
    setState(prev => ({
      ...prev,
      gameStarted: false,
      isGameOver: false,
      drawnNumbers: [],
      currentBall: null,
      rivals: []
    }));
  };

  const drawBall = useCallback(async () => {
    setState(prev => {
      if (prev.isGameOver || prev.drawnNumbers.length >= 75) return prev;

      let nextNum: number;
      do {
        nextNum = Math.floor(Math.random() * 75) + 1;
      } while (prev.drawnNumbers.includes(nextNum));

      const newDrawn = [...prev.drawnNumbers, nextNum];

      // Update rivals
      const newRivals = prev.rivals.map(rival => {
        // Rivals have a 25% chance of marking a spot if it matches a card they "might" have
        // Simulating progress
        if (Math.random() > 0.75 && rival.markedCount < 24) {
          return { ...rival, markedCount: rival.markedCount + 1 };
        }
        return rival;
      });

      // Check if any rival won
      const rivalWinner = newRivals.find(r => r.markedCount >= 24);

      return {
        ...prev,
        drawnNumbers: newDrawn,
        currentBall: nextNum,
        rivals: newRivals,
        isGameOver: !!rivalWinner,
        commentary: `Drawing number... ${nextNum}!`,
      };
    });

    // Get AI Commentary asynchronously
    const lastNum = state.currentBall; // This is actually slightly stale here, but drawBall triggers it
  }, [state.currentBall]);

  useEffect(() => {
    if (state.currentBall) {
      getBingoCommentary(state.currentBall).then(comment => {
        setState(prev => ({ ...prev, commentary: comment }));
      });
    }
  }, [state.currentBall]);

  useEffect(() => {
    if (state.gameStarted && !state.isGameOver) {
      timerRef.current = setInterval(() => {
        drawBall();
      }, SPEED_MS[state.difficulty]);
    } else {
      if (timerRef.current) clearInterval(timerRef.current);
    }
    return () => { if (timerRef.current) clearInterval(timerRef.current); };
  }, [state.gameStarted, state.isGameOver, state.difficulty, drawBall]);

  const markCell = (row: number, col: number) => {
    if (state.isGameOver) return;

    const cell = state.card[row][col];
    if (cell.number === 'FREE') return;

    if (state.drawnNumbers.includes(cell.number as number)) {
      const newCard = [...state.card];
      newCard[row][col].isMarked = true;

      const { hasWon, winningCells } = checkWin(newCard);

      if (hasWon) {
        winningCells.forEach(([r, c]) => {
          newCard[r][c].isWinningCell = true;
        });
        getWinCelebration("YOU").then(msg => {
          setState(prev => ({ 
            ...prev, 
            card: newCard, 
            hasWon: true, 
            isGameOver: true, 
            commentary: msg 
          }));
        });
      } else {
        setState(prev => ({ ...prev, card: newCard }));
      }
    }
  };

  const winningRival = state.rivals.find(r => r.markedCount >= 24);

  return (
    <div className="max-w-6xl mx-auto px-4 py-8 flex flex-col items-center">
      <header className="mb-8 text-center">
        <h1 className="text-5xl md:text-7xl font-bungee text-transparent bg-clip-text bg-gradient-to-r from-amber-400 via-rose-500 to-indigo-400 drop-shadow-lg mb-2">
          BINGO BLITZ
        </h1>
        <p className="text-indigo-200 font-semibold tracking-widest uppercase text-sm">Enhanced by Gemini Intelligence</p>
      </header>

      {!state.gameStarted ? (
        <div className="flex flex-col items-center gap-8 bg-white/10 backdrop-blur-xl p-12 rounded-3xl border border-white/20 shadow-2xl animate-in fade-in zoom-in duration-500">
          <div className="flex flex-col items-center gap-2">
            <span className="text-amber-400 font-bold">SELECT SPEED</span>
            <div className="flex gap-2">
              {(['Slow', 'Normal', 'Fast'] as const).map(speed => (
                <button
                  key={speed}
                  onClick={() => setState(prev => ({ ...prev, difficulty: speed }))}
                  className={`px-4 py-2 rounded-lg font-bold transition-all ${state.difficulty === speed ? 'bg-amber-500 text-white shadow-lg scale-105' : 'bg-indigo-900/50 text-indigo-300'}`}
                >
                  {speed}
                </button>
              ))}
            </div>
          </div>
          <button
            onClick={startGame}
            className="group relative px-12 py-6 bg-indigo-600 rounded-2xl font-bungee text-3xl text-white hover:bg-indigo-500 transition-all shadow-xl hover:shadow-indigo-500/20 active:scale-95"
          >
            <div className="absolute -inset-1 bg-gradient-to-r from-amber-400 to-rose-500 rounded-2xl blur opacity-25 group-hover:opacity-75 transition duration-1000"></div>
            <span className="relative">START GAME</span>
          </button>
        </div>
      ) : (
        <div className="w-full grid grid-cols-1 lg:grid-cols-12 gap-8 items-start">
          {/* Left Column: Game Stats & Commentary */}
          <div className="lg:col-span-3 flex flex-col gap-6">
            <div className="bg-white/10 backdrop-blur-md rounded-2xl p-6 border border-white/20">
              <h3 className="text-amber-400 font-bungee mb-2">Game Info</h3>
              <div className="space-y-2">
                <div className="flex justify-between">
                  <span className="text-indigo-200 text-sm">Balls Drawn:</span>
                  <span className="font-bold">{state.drawnNumbers.length}</span>
                </div>
                <div className="flex justify-between">
                  <span className="text-indigo-200 text-sm">Speed:</span>
                  <span className="font-bold">{state.difficulty}</span>
                </div>
              </div>
              <button 
                onClick={resetGame}
                className="mt-6 w-full py-2 bg-rose-500/20 text-rose-300 rounded-lg border border-rose-500/30 hover:bg-rose-500/30 transition-all text-sm font-bold"
              >
                QUIT GAME
              </button>
            </div>

            <div className="bg-white/10 backdrop-blur-md rounded-2xl p-6 border border-white/20">
              <h3 className="text-amber-400 font-bungee mb-2">Ball History</h3>
              <div className="flex flex-wrap gap-2 max-h-48 overflow-y-auto pr-2 scrollbar-thin scrollbar-thumb-indigo-500">
                {state.drawnNumbers.slice().reverse().map((n, i) => (
                  <div key={i} className="w-8 h-8 rounded-full bg-indigo-900/80 flex items-center justify-center text-xs font-bold border border-indigo-400/30">
                    {n}
                  </div>
                ))}
              </div>
            </div>
          </div>

          {/* Middle Column: The Action */}
          <div className="lg:col-span-6 flex flex-col items-center gap-6">
            <BingoBall number={state.currentBall} commentary={state.commentary} />

            <BingoBoard 
              card={state.card} 
              onCellClick={markCell} 
              isGameOver={state.isGameOver} 
            />

            {state.isGameOver && (
              <div className="w-full text-center p-8 bg-indigo-950/80 backdrop-blur-xl rounded-3xl border-2 border-amber-500/50 animate-in fade-in slide-in-from-bottom-10 duration-700">
                <h2 className="text-4xl font-bungee text-amber-400 mb-2">
                  {state.hasWon ? 'BINGO! YOU WON!' : `${winningRival?.name} WON!`}
                </h2>
                <p className="text-indigo-200 mb-6 italic">"{state.commentary}"</p>
                <button
                  onClick={startGame}
                  className="px-8 py-3 bg-amber-500 text-white font-bungee rounded-xl shadow-lg hover:bg-amber-400 transition-all"
                >
                  PLAY AGAIN
                </button>
              </div>
            )}
          </div>

          {/* Right Column: Rivals */}
          <div className="lg:col-span-3">
            <RivalList rivals={state.rivals} />
          </div>
        </div>
      )}

      {/* Footer / Info */}
      <footer className="mt-16 text-indigo-400/50 text-xs flex gap-4 uppercase tracking-widest font-bold">
        <span>© 2024 GEMINI BINGO BLITZ</span>
        <span>•</span>
        <span>POWERED BY GOOGLE GEN AI</span>
      </footer>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { BingoBoard } from './components/BingoBoard';
import { BingoBall } from './components/BingoBall';
import { RivalList } from './components/RivalList';
import { GameState, RivalPlayer, BingoCard } from './types';
import { generateCard, checkWin } from './utils/bingoLogic';
import { SPEED_MS, RIVAL_NAMES } from './constants';
