const App: React.FC = () => {
  const [state, setState] = useState<GameState>({
    drawnNumbers: [],
    currentBall: null,
    card: generateCard(),
    isGameOver: false,
    hasWon: false,
    commentary: "Welcome to Gemini Bingo Blitz!",
    gameStarted: false,
    difficulty: 'Normal',
    rivals: []
  });

  // Fix: Use ReturnType<typeof setInterval> instead of NodeJS.Timeout to resolve the namespace error in browser environments
  const timerRef = useRef<ReturnType<typeof setInterval> | null>(null);

  const initRivals = (): RivalPlayer[] => {
    return RIVAL_NAMES.slice(0, 5).map((name, i) => ({
