import { BINGO_RANGES } from '../constants';

/**
 * A simple deterministic seedable random number generator (Mulberry32)
 */
export const createPRNG = (seed: string) => {
  let h = 0;
  for (let i = 0; i < seed.length; i++) {
    h = Math.imul(31, h) + seed.charCodeAt(i) | 0;
  }
  let a = h;
  return () => {
    let t = a += 0x6D2B79F5;
    t = Math.imul(t ^ t >>> 15, t | 1);
    t ^= t + Math.imul(t ^ t >>> 7, t | 61);
    return ((t ^ t >>> 14) >>> 0) / 4294967296;
  };
};

const getRandomInRange = (min: number, max: number, count: number, prng: () => number): number[] => {
  const nums = new Set<number>();
  while (nums.size < count) {
    nums.add(Math.floor(prng() * (max - min + 1)) + min);
  }
  return Array.from(nums).sort((a, b) => a - b);
};

export const generateCard = (seed: string): BingoCard => {
  const prng = createPRNG(seed);
  const columns: BingoColumn[] = ['B', 'I', 'N', 'G', 'O'];
  const card: BingoCard = [];

  for (let i = 0; i < 5; i++) {
    const colKey = columns[i];
    const { min, max } = BINGO_RANGES[colKey];
    const colNumbers = getRandomInRange(min, max, 5, prng);

    const row: BingoCell[] = colNumbers.map((num, idx) => ({
      number: (i === 2 && idx === 2) ? 'FREE' : num,
      isMarked: (i === 2 && idx === 2),
      isWinningCell: false
    }));
    card.push(row);
  }

  const rows: BingoCard = Array.from({ length: 5 }, () => Array(5).fill(null));
  for (let c = 0; c < 5; c++) {
    for (let r = 0; r < 5; r++) {
      rows[r][c] = card[c][r];
    }
  }

  return rows;
};

export const checkWin = (card: BingoCard): { hasWon: boolean; winningCells: [number, number][] } => {
  const winningCells: [number, number][] = [];

  for (let r = 0; r < 5; r++) {
    if (card[r].every(cell => cell.isMarked)) {
      card[r].forEach((_, c) => winningCells.push([r, c]));
      return { hasWon: true, winningCells };
    }
  }

  for (let c = 0; c < 5; c++) {
    let allMarked = true;
    for (let r = 0; r < 5; r++) {
      if (!card[r][c].isMarked) {
        allMarked = false;
        break;
      }
    }
    if (allMarked) {
      for (let r = 0; r < 5; r++) winningCells.push([r, c]);
      return { hasWon: true, winningCells };
    }
  }

  let diag1 = true;
  for (let i = 0; i < 5; i++) {
    if (!card[i][i].isMarked) diag1 = false;
  }
  if (diag1) {
    for (let i = 0; i < 5; i++) winningCells.push([i, i]);
    return { hasWon: true, winningCells };
  }

  let diag2 = true;
  for (let i = 0; i < 5; i++) {
    if (!card[i][4 - i].isMarked) diag2 = false;
  }
  if (diag2) {
    for (let i = 0; i < 5; i++) winningCells.push([i, 4 - i]);
    return { hasWon: true, winningCells };
  }

  return { hasWon: false, winningCells: [] };
};

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { BingoBoard } from './components/BingoBoard';
import { BingoBall } from './components/BingoBall';
import { RivalList } from './components/RivalList';
import { GameState, RivalPlayer } from './types';
import { generateCard, checkWin, createPRNG } from './utils/bingoLogic';
import { SPEED_MS, RIVAL_NAMES } from './constants';
import { getBingoCommentary, getWinCelebration } from './services/geminiService';

const App: React.FC = () => {
  const [roomCode, setRoomCode] = useState("");
  const [playerName, setPlayerName] = useState("Player 1");
  const [state, setState] = useState<GameState>({
    drawnNumbers: [],
    currentBall: null,
    card: generateCard("default"),
    isGameOver: false,
    hasWon: false,
    commentary: "Welcome to Gemini Bingo Blitz!",
    gameStarted: false,
    difficulty: 'Normal',
    rivals: []
  });

  const [isOfflineMode] = useState(!process.env.API_KEY);
  const timerRef = useRef<ReturnType<typeof setInterval> | null>(null);
  const prngRef = useRef<() => number>(() => Math.random());

  const initRivals = (): RivalPlayer[] => {
    return RIVAL_NAMES.slice(0, 5).map((name, i) => ({
      id: `rival-${i}`,
      name,
      markedCount: 0,
      isWinner: false,
      avatar: ""
    }));
  };

  const startGame = () => {
    const finalSeed = roomCode || Math.random().toString(36).substring(7);
    // Use player name + seed for unique card, but same seed for same ball sequence
    const cardSeed = finalSeed + playerName; 

    // Initialize the seeded generator for the draws
    prngRef.current = createPRNG(finalSeed);

    setState(prev => ({
      ...prev,
      drawnNumbers: [],
      currentBall: null,
      card: generateCard(cardSeed),
      isGameOver: false,
      hasWon: false,
      gameStarted: true,
      commentary: "And we're off! Good luck everyone.",
      rivals: initRivals()
    }));
  };

  const resetGame = () => {
    if (timerRef.current) clearInterval(timerRef.current);
    setState(prev => ({
      ...prev,
      gameStarted: false,
      isGameOver: false,
      drawnNumbers: [],
      currentBall: null,
      rivals: []
    }));
  };

  const drawBall = useCallback(async () => {
    setState(prev => {
      if (prev.isGameOver || prev.drawnNumbers.length >= 75) return prev;

      let nextNum: number;
      // Use the seeded PRNG instead of Math.random
      const getNext = () => Math.floor(prngRef.current() * 75) + 1;

      do {
        nextNum = getNext();
      } while (prev.drawnNumbers.includes(nextNum));

      const newDrawn = [...prev.drawnNumbers, nextNum];

      const newRivals = prev.rivals.map(rival => {
        // Rivals also behave deterministically if they use the same seed
        if (prngRef.current() > 0.85 && rival.markedCount < 24) {
          return { ...rival, markedCount: rival.markedCount + 1 };
        }
        return rival;
      });

      const rivalWinner = newRivals.find(r => r.markedCount >= 24);

      return {
        ...prev,
        drawnNumbers: newDrawn,
        currentBall: nextNum,
        rivals: newRivals,
        isGameOver: !!rivalWinner,
        commentary: prev.commentary
      };
    });
  }, []);

  useEffect(() => {
    if (state.currentBall) {
      getBingoCommentary(state.currentBall).then(comment => {
        setState(prev => ({ ...prev, commentary: comment }));
      });
    }
  }, [state.currentBall]);

  useEffect(() => {
    if (state.gameStarted && !state.isGameOver) {
      timerRef.current = setInterval(() => {
        drawBall();
      }, SPEED_MS[state.difficulty]);
    } else {
      if (timerRef.current) clearInterval(timerRef.current);
    }
    return () => { if (timerRef.current) clearInterval(timerRef.current); };
  }, [state.gameStarted, state.isGameOver, state.difficulty, drawBall]);

  const markCell = (row: number, col: number) => {
    if (state.isGameOver) return;
    const cell = state.card[row][col];
    if (cell.number === 'FREE') return;
    if (state.drawnNumbers.includes(cell.number as number)) {
      const newCard = [...state.card];
      newCard[row][col].isMarked = true;
      const { hasWon, winningCells } = checkWin(newCard);
      if (hasWon) {
        winningCells.forEach(([r, c]) => { newCard[r][c].isWinningCell = true; });
        getWinCelebration("YOU").then(msg => {
          setState(prev => ({ ...prev, card: newCard, hasWon: true, isGameOver: true, commentary: msg }));
        });
      } else {
        setState(prev => ({ ...prev, card: newCard }));
      }
    }
  };

  const winningRival = state.rivals.find(r => r.markedCount >= 24);

  return (
    <div className="max-w-6xl mx-auto px-4 py-8 flex flex-col items-center">
      <header className="mb-8 text-center relative">
        {isOfflineMode && (
          <div className="absolute -top-6 left-1/2 -translate-x-1/2 bg-white/10 px-3 py-1 rounded-full border border-white/10 text-[10px] uppercase tracking-widest text-indigo-300 font-bold">
            Local Mode Enabled
          </div>
        )}
        <h1 className="text-5xl md:text-7xl font-bungee text-transparent bg-clip-text bg-gradient-to-r from-amber-400 via-rose-500 to-indigo-400 drop-shadow-lg mb-2">
          BINGO BLITZ
        </h1>
        <p className="text-indigo-200 font-semibold tracking-widest uppercase text-sm">Offline Multiplayer Sync</p>
      </header>

      {!state.gameStarted ? (
        <div className="w-full max-w-2xl flex flex-col gap-8 bg-white/10 backdrop-blur-xl p-8 md:p-12 rounded-3xl border border-white/20 shadow-2xl animate-in fade-in zoom-in duration-500">
          <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
            <div className="flex flex-col gap-4">
              <label className="text-amber-400 font-bungee text-sm">Room Settings</label>
              <input 
                type="text" 
                placeholder="Enter Room Code (to play together)"
                className="w-full bg-indigo-950/50 border border-indigo-500/30 rounded-xl px-4 py-3 text-white placeholder:text-indigo-300/50 focus:outline-none focus:ring-2 focus:ring-amber-500 transition-all"
                value={roomCode}
                onChange={(e) => setRoomCode(e.target.value)}
              />
              <input 
                type="text" 
                placeholder="Your Name"
                className="w-full bg-indigo-950/50 border border-indigo-500/30 rounded-xl px-4 py-3 text-white placeholder:text-indigo-300/50 focus:outline-none focus:ring-2 focus:ring-amber-500 transition-all"
                value={playerName}
                onChange={(e) => setPlayerName(e.target.value)}
              />
            </div>

            <div className="flex flex-col gap-4">
              <label className="text-amber-400 font-bungee text-sm">Game Speed</label>
              <div className="grid grid-cols-1 gap-2">
                {(['Slow', 'Normal', 'Fast'] as const).map(speed => (
                  <button
                    key={speed}
                    onClick={() => setState(prev => ({ ...prev, difficulty: speed }))}
                    className={`px-4 py-3 rounded-xl font-bold transition-all text-left ${state.difficulty === speed ? 'bg-amber-500 text-white shadow-lg' : 'bg-indigo-900/50 text-indigo-300 hover:bg-indigo-900/80'}`}
                  >
                    {speed} {speed === 'Normal' && '⚡️'}
                  </button>
                ))}
              </div>
            </div>
          </div>

          <button
            onClick={startGame}
            className="group relative w-full py-6 bg-indigo-600 rounded-2xl font-bungee text-3xl text-white hover:bg-indigo-500 transition-all shadow-xl hover:shadow-indigo-500/20 active:scale-95"
          >
            <div className="absolute -inset-1 bg-gradient-to-r from-amber-400 to-rose-500 rounded-2xl blur opacity-25 group-hover:opacity-75 transition duration-1000"></div>
            <span className="relative">START BINGO</span>
          </button>

          <p className="text-center text-indigo-300/60 text-xs">
            Tip: Share the Room Code with friends nearby to sync your drawn numbers!
          </p>
        </div>
      ) : (
        <div className="w-full grid grid-cols-1 lg:grid-cols-12 gap-8 items-start">
          <div className="lg:col-span-3 flex flex-col gap-6">
            <div className="bg-white/10 backdrop-blur-md rounded-2xl p-6 border border-white/20">
              <div className="flex items-center justify-between mb-4">
                <h3 className="text-amber-400 font-bungee text-sm">Session</h3>
                <span className="text-[10px] bg-indigo-500/30 px-2 py-1 rounded text-white font-mono">{roomCode || 'SOLO'}</span>
              </div>
              <div className="space-y-2">
                <div className="flex justify-between">
                  <span className="text-indigo-200 text-sm">Drawn:</span>
                  <span className="font-bold">{state.drawnNumbers.length}</span>
                </div>
                <div className="flex justify-between">
                  <span className="text-indigo-200 text-sm">Player:</span>
                  <span className="font-bold text-amber-400 truncate max-w-[100px]">{playerName}</span>
                </div>
              </div>
              <button 
                onClick={resetGame}
                className="mt-6 w-full py-2 bg-rose-500/20 text-rose-300 rounded-lg border border-rose-500/30 hover:bg-rose-500/30 transition-all text-sm font-bold"
              >
                LEAVE GAME
              </button>
            </div>

            <div className="bg-white/10 backdrop-blur-md rounded-2xl p-6 border border-white/20">
              <h3 className="text-amber-400 font-bungee mb-2 text-sm">History</h3>
              <div className="flex flex-wrap gap-2 max-h-48 overflow-y-auto pr-2">
                {state.drawnNumbers.slice().reverse().map((n, i) => (
                  <div key={i} className="w-8 h-8 rounded-full bg-indigo-900/80 flex items-center justify-center text-xs font-bold border border-indigo-400/30">
                    {n}
                  </div>
                ))}
              </div>
            </div>
          </div>

          <div className="lg:col-span-6 flex flex-col items-center gap-6">
            <BingoBall number={state.currentBall} commentary={state.commentary} />
            <BingoBoard card={state.card} onCellClick={markCell} isGameOver={state.isGameOver} />

            {state.isGameOver && (
              <div className="w-full text-center p-8 bg-indigo-950/80 backdrop-blur-xl rounded-3xl border-2 border-amber-500/50 animate-in fade-in slide-in-from-bottom-10 duration-700">
                <h2 className="text-4xl font-bungee text-amber-400 mb-2">
                  {state.hasWon ? 'BINGO!' : 'ROUND END'}
                </h2>
                <p className="text-white font-bold text-xl mb-2">
                   {state.hasWon ? 'Victory is yours!' : `${winningRival?.name} won this time!`}
                </p>
                <p className="text-indigo-200 mb-6 italic text-sm">"{state.commentary}"</p>
                <button
                  onClick={startGame}
                  className="px-8 py-3 bg-amber-500 text-white font-bungee rounded-xl shadow-lg hover:bg-amber-400 transition-all"
                >
                  NEW ROUND
                </button>
              </div>
            )}
          </div>

          <div className="lg:col-span-3">
            <RivalList rivals={state.rivals} />
          </div>
        </div>
      )}

      <footer className="mt-16 text-indigo-400/50 text-[10px] flex gap-4 uppercase tracking-[0.2em] font-bold">
        <span>Room ID: {roomCode || 'None'}</span>
        <span>•</span>
        <span>Deterministic Offline Sync</span>
      </footer>
    </div>
  );
};

export default App;

