        return rival;
      });

      const rivalWinner = newRivals.find(r => r.markedCount >= 24);
      if (rivalWinner) {
        playSound('loss');
        stopBackgroundMusic();
      }

      return {
        ...prev,
        drawnNumbers: newDrawn,
        currentBall: nextNum,
        rivals: newRivals,
